+++ b/src/screens/MyOrdersDetails/utils.ts
@@ -0,0 +1,124 @@
+import type moment from 'moment';
+import type { MyOrdersDetailProps, TransactionType } from './Models';
+
+export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
+
+export const getTransactionGainType = (
+  transaction: MyOrdersDetailProps['transaction'],
+): TransactionGainType => {
+  if (!transaction) return 'CARD';
+
+  const provider = transaction.details?.provider?.toLowerCase() || '';
+
+  if (provider.includes('cashback')) {
+    return 'CASHBACK';
+  }
+
+  const icon = transaction.icon?.toLowerCase() || '';
+  const description = transaction.description?.toLowerCase() || '';
+
+  const tagIndicators = [
+    'tag',
+    'pedágio',
+    'pedagio',
+    'estacionamento',
+    'abastecimento',
+    'abastece',
+    'drive',
+    'lava',
+    'rápido',
+  ];
+
+  const isTag = tagIndicators.some(
+    indicator =>
+      icon.includes(indicator) ||
+      description.includes(indicator) ||
+      provider.includes(indicator),
+  );
+
+  return isTag ? 'TAG' : 'CARD';
+};
+
+export const getFormattedPointsValue = (
+  amount: number,
+  type: TransactionType,
+): string => {
+  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
+  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
+  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
+};
+
+export const getFormattedHighlightText = (
+  date: string,
+  _gainType: TransactionGainType,
+  momentInstance: typeof moment,
+): string => {
+  const transactionDate = momentInstance(date);
+  const day = transactionDate.format('DD');
+  const month = transactionDate.format('MMM').toLowerCase();
+  const year = transactionDate.format('YYYY');
+  const time = transactionDate.format('HH:mm');
+
+  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
+};
+
+export const getFormattedPointsValueForMarketplace = (
+  valuePoints: number,
+): string => {
+  const absValue = Math.abs(valuePoints);
+  const label = absValue === 1 ? 'ponto' : 'pontos';
+  return `${absValue.toLocaleString('pt-BR')} ${label}`;
+};
+
+export const getPaymentTypeLabel = (paymentType: string): string => {
+  const labels: Record<string, string> = {
+    POINTS: 'Pontos',
+    CARD: 'Cartão',
+    PIX: 'PIX',
+  };
+  return labels[paymentType] || paymentType;
+};
+
+export const getMarketplaceTitle = (
+  transaction: MyOrdersDetailProps['transaction'],
+): string | null => {
+  if (!transaction?.marketplace?.orders) return null;
+
+  const allItems: Array<{ name: string }> = [];
+  transaction.marketplace.orders.forEach(order => {
+    if (order.items) {
+      allItems.push(...order.items);
+    }
+  });
+
+  if (allItems.length === 0) return null;
+  if (allItems.length === 1) return allItems[0].name;
+
+  const firstItemName = allItems[0].name;
+  const secondItemFirstWord = allItems[1].name.split(' ')[0];
+
+  if (allItems.length === 2) {
+    return `${firstItemName} e ${secondItemFirstWord}`;
+  }
+
+  const remainingCount = allItems.length - 2;
+  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
+};
+
+export const getCleanedImageUrl = (
+  url: string | undefined,
+): string | undefined => {
+  if (!url) return undefined;
+
+  let cleanedUrl = url.trim();
+
+  if (cleanedUrl.startsWith('imageUrl:')) {
+    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
+  }
+
+  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
+    return cleanedUrl;
+  }
+
+  return undefined;
+};
diff --git a/src/screens/MyOrdersDetails/view.tsx b/src/screens/MyOrdersDetails/view.tsx
new file mode 100644
index 00000000..d38181c4
--- /dev/null
+++ b/src/screens/MyOrdersDetails/view.tsx
@@ -0,0 +1,413 @@
+import {
+  Alert,
+  BackDropBottom,
+  Box,
+  Button,
+  CardActivity,
+  DetailTransactionValue,
+  SeparatorHorizontal,
+  TagLabel,
+  Text,
+} from '@semparar/design-system-app';
+import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
+import theme from '@semparar/design-system-app/src/styles/theme';
+import React, { FC } from 'react';
+import { ActivityIndicator, Linking } from 'react-native';
+import { eventSelectContent } from '~/constants/functions';
+import ApiError from '../../atomic/organisms/ApiError';
+import BasicScreen from '../../atomic/templates/BasicScreen';
+import type { MyOrdersDetailProps } from './Models';
+import { STATUS_COLORS } from './Models';
+
+const MyOrdersDetailView: FC<MyOrdersDetailProps> = ({
+  handleGoBack,
+  transaction,
+  modalizeRef,
+  modalizeRefInfo,
+  handleOpenReportProblem,
+  handleCloseReportProblem,
+  handleCloseInfo,
+  isLoading,
+  hasError,
+  handleRetry,
+  isCashback,
+  cardTitle,
+  formattedPointsValue,
+  highlightText,
+  formattedCurrencyValue,
+  marketplaceContent,
+  showOrderNumber,
+  showStatus,
+  showValue,
+  height,
+}) => {
+  if (hasError) {
+    return (
+      <BasicScreen
+        title="Detalhes do pedido"
+        leftIconOnPress={handleGoBack}
+        errorButtonOnPress={handleRetry || (() => {})}
+      >
+        <ApiError
+          title="Algo deu errado!"
+          subTitle="Por favor, tente de novo."
+          isLoading={isLoading}
+          onPress={handleRetry || (() => {})}
+        />
+      </BasicScreen>
+    );
+  }
+
+  if (isLoading && !transaction) {
+    return (
+      <BasicScreen
+        title="Detalhes do pedido"
+        leftIconOnPress={handleGoBack}
+        hasScroll
+        errorButtonOnPress={() => {}}
+      >
+        <Box flex={1} justify="center" align="center" minHeight={400}>
+          <ActivityIndicator size="large" color={theme.colors.BRAND_BASE_01} />
+        </Box>
+      </BasicScreen>
+    );
+  }
+
+  if (!transaction) {
+    return null;
+  }
+
+  const renderDivider = () => (
+    <SeparatorHorizontal
+      borderWidth="smaller"
+      borderColor="BRAND_COMPLEMENT_02"
+      height={1}
+      width="100%"
+      mt="xxxxs"
+    />
+  );
+
+  const renderMarketplaceContent = () => {
+    if (!marketplaceContent) return null;
+
+    return (
+      <>
+        <Text
+          type="paragraphXL"
+          color="BRAND_COMPLEMENT_01"
+          mb="xxxxs"
+          mt="xxxxs"
+        >
+          Número do pedido
+        </Text>
+        <Text type="paragraphMD" color="INTENSE_COLOR_03">
+          #{marketplaceContent.orderNumber}
+        </Text>
+        {marketplaceContent.status && (
+          <>
+            {renderDivider()}
+            <Text
+              type="paragraphXL"
+              color="BRAND_COMPLEMENT_01"
+              mb="xxxxs"
+              mt="xxxxs"
+            >
+              Status do pedido
+            </Text>
+            <TagLabel
+              type={(marketplaceContent.statusColor as never) || 'neutral'}
+              text={marketplaceContent.status}
+              showSpacing
+            />
+          </>
+        )}
+        {marketplaceContent.paymentType && (
+          <>
+            {renderDivider()}
+            <Text
+              type="paragraphXL"
+              color="BRAND_COMPLEMENT_01"
+              mb="xxxxs"
+              mt="xxxxs"
+            >
+              Forma de pagamento
+            </Text>
+            <Text type="paragraphMD" color="INTENSE_COLOR_03">
+              {marketplaceContent.paymentType}
+            </Text>
+          </>
+        )}
+        {marketplaceContent.shippingValuePoints !== undefined &&
+          marketplaceContent.shippingValuePoints !== null && (
+            <>
+              {renderDivider()}
+              <Text
+                type="paragraphXL"
+                color="BRAND_COMPLEMENT_01"
+                mb="xxxxs"
+                mt="xxxxs"
+              >
+                Frete
+              </Text>
+              <Text type="paragraphMD" color="INTENSE_COLOR_03">
+                {marketplaceContent.shippingValuePoints}
+              </Text>
+            </>
+          )}
+        {marketplaceContent.valuePoints !== undefined &&
+          marketplaceContent.valuePoints !== null && (
+            <>
+              {renderDivider()}
+              <Text
+                type="paragraphXL"
+                color="BRAND_COMPLEMENT_01"
+                mb="xxxxs"
+                mt="xxxxs"
+              >
+                Valor total
+              </Text>
+              <Text type="paragraphMD" color="INTENSE_COLOR_03">
+                {marketplaceContent.valuePoints}
+              </Text>
+            </>
+          )}
+        {marketplaceContent.vendorName && (
+          <>
+            {renderDivider()}
+            <Text
+              type="paragraphXL"
+              color="BRAND_COMPLEMENT_01"
+              mb="xxxxs"
+              mt="xxxxs"
+            >
+              Parceiro: {marketplaceContent.vendorName}
+            </Text>
+          </>
+        )}
+        {marketplaceContent.items.map((item, itemIndex: number) => (
+          <CardActivity
+            key={itemIndex}
+            mt="nano"
+            title={item.name}
+            titleTextType="paragraphMD"
+            description={`Quantidade: ${item.quantity}\nValor: ${item.valuePoints}`}
+            descriptionTextType="paragraphSM"
+            showImage={!!item.cleanedImageUrl}
+            image={
+              item.cleanedImageUrl ? { uri: item.cleanedImageUrl } : undefined
+            }
+            showIcon={false}
+            iconRight={null as never}
+            hideBorder={false}
+          />
+        ))}
+
+        <Alert
+          title="Detalhes da entrega"
+          mt="meddium"
+          label="Você pode acompanhar a entrega do seu pedido pelo site do parceiro."
+          numberOfLines={2}
+          type="highlight"
+          icon="icon-truck"
+          hasIconBackground
+          bgIconColor="BRAND_COMPLEMENT_03"
+        />
+      </>
+    );
+  };
+
+  return (
+    <>
+      <BasicScreen
+        title="Detalhes do pedido"
+        isLoading={isLoading}
+        leftIconOnPress={handleGoBack}
+        rightIcon={
+          isCashback && !transaction?.marketplace ? 'icon-help' : undefined
+        }
+        rightIconOnPress={undefined}
+        hasRightIcon={isCashback && !transaction?.marketplace}
+        hasScroll
+        errorButtonOnPress={() => {}}
+      >
+        <DetailTransactionValue
+          icon={transaction.icon as never}
+          title={cardTitle}
+          titleColor="BRAND_COMPLEMENT_01"
+          iconBgColor="BRAND_COMPLEMENT_03"
+          points={formattedPointsValue}
+          bgColor="BRAND_COMPLEMENT_02"
+          pointsColor={
+            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
+              ? 'PLUS_COLOR_02'
+              : ('INTENSE_COLOR_05' as const)
+          }
+        />
+
+        <Box ml="smaller" mr="smaller" mt="xs" flex={1}>
+          <TagLabel
+            icon={undefined}
+            type="neutral"
+            text={highlightText}
+            showSpacing
+            mb="xs"
+          />
+
+          <Box flex={1} width="100%">
+            {showOrderNumber && (
+              <>
+                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
+                  Número do pedido
+                </Text>
+                <Text type="paragraphMD" color="INTENSE_COLOR_03">
+                  #{transaction.id}
+                </Text>
+              </>
+            )}
+
+            {showStatus && transaction.status && (
+              <>
+                {renderDivider()}
+                <Text
+                  type="paragraphXL"
+                  color="BRAND_COMPLEMENT_01"
+                  mb="xxxxs"
+                  mt="xxxxs"
+                >
+                  Status do pedido
+                </Text>
+                <TagLabel
+                  type={STATUS_COLORS[transaction.status] || 'neutral'}
+                  text={transaction.status}
+                  showSpacing
+                />
+              </>
+            )}
+
+            {showValue && (
+              <>
+                {renderDivider()}
+                <Text
+                  type="paragraphXL"
+                  color="BRAND_COMPLEMENT_01"
+                  mb="xxxxs"
+                  mt="xxxxs"
+                >
+                  Valor
+                </Text>
+                <Text type="paragraphMD" color="INTENSE_COLOR_03">
